            contentTextView.text = "Image URI: $imageUri"
            displayImage(imageUri)
            processImage(imageUri)
            Log.d(TAG, "Shared image received: $imageUri")
        } else {
            statusTextView.text = "Shared image was empty"
            Log.w(TAG, "Shared image URI was null")
        }
    }

    private fun handleSharedMultipleImages(intent: Intent) {
        val imageUris: ArrayList<Uri>? = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM, Uri::class.java)
        } else {
            @Suppress("DEPRECATION")
